UPDATE radio_channels SET metadata = JSON_SET(metadata, '$.description', 'Electronic gaming music and hacker culture.', '$.source', 'SomaFM DEF CON', '$.targetAudience', 'Gamers and tech enthusiasts') WHERE id = 48

